module RefModule(
    input clk,
    input reset,
    input enable,
    output reg [3:0] q,
    output carry
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            // Synchronous reset: Reset the counter to 4'b0000
            q <= 4'b0000;
        end else if (enable) begin
            // Counter increments when enabled
            q <= q + 1;
        end
    end

    // Carry-out when counter overflows
    assign carry = enable & (q == 4'b1111);

endmodule
